```python
from flask import request, render_template

from .models import Page

def pages(*args, **kwargs):
    return [{'text': page.name, 'url': page.url}
            for page in Pages.query.all()]

@app.route("/content/<page_name>")
@menu.register_menu(app, '.<some page>', '',
                                 dynamic_list_constructor=pages)
def a_page(page_name):
    page = Page.query.filter_by(name=page_name).one_or_404()
    return render_template('page.html', page=page)
```

