I scratched together the following code that builds on the lazy_attribute solution presented by @samuelcolvin:
```python
# students and clients both have a "user" field, students and clients should always share
# the same company defined at user.company
import six
import factory.django
from models import Student
from factories import UserFactory, ClientFactory

gen_user = factory.LazyAttribute(lambda o: UserFactory(company=o.factory_parent.user.company))


class ChainedSubFactoryMeta(factory.base.FactoryMetaClass):
    def __new__(cls, name, bases, attrs):
        for name, attr in attrs.items():
            if isinstance(attr, factory.SubFactory):
                attrs[name] = factory.lazy_attribute(
                    lambda self, _name=name, _sub_factory=attr.get_factory(): _sub_factory(
                        **self._Resolver__declarations.contexts.get(name, {})
                    )
                )
        return super(ChainedSubFactoryMeta, cls).__new__(cls, name, bases, attrs)


class ChainedDjangoModelFactory(six.with_metaclass(ChainedSubFactoryMeta, factory.DjangoModelFactory)):
    pass


class StudentFactory(ChainedDjangoModelFactory):
    class Meta:
        model = Student

    user = factory.SubFactory(UserFactory)
    client = factory.SubFactory(ClientFactory, user=gen_user)
```

Perhaps something like this could be used as the basis for a PR.

